                    expansion.push(Token::control_sequence(target_id, 0, 0));
                    expansion.push(Token::character('{', CatCode::BeginGroup, 0, 0));
                    expansion.extend(item);
                    expansion.push(Token::character('}', CatCode::EndGroup, 0, 0));
