    #[test]
    fn render_event_capture_records_citation_variants() {
        let source = r"\begin{document}\citep[see][p.~3]{alpha,beta}\citet*{gamma}\parencite{delta}\textcite{epsilon}\citep*{zeta}\citealt*{eta}\citealp*{theta}\Textcite*{iota}\Citealt{lambda}\Citealp{mu}\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);
        let citations = outcome
            .render_events
            .iter()
            .filter_map(|event| match &event.event {
                RenderEvent::InlineCitation(citation) => {
                    Some((citation, &event.meta.source.primary))
                }
                _ => None,
            })
            .collect::<Vec<_>>();

        assert_eq!(citations.len(), 10);
        assert_eq!(citations[0].0.command, "citep");
        assert_eq!(citations[0].0.style_hint, CitationStyleHint::Parenthetical);
        assert_eq!(
            citations[0].0.keys,
            vec!["alpha".to_string(), "beta".to_string()]
        );
        assert!(matches!(
            citations[0].1,
            tex_render_model::ProvenanceSpan::File(span)
                if span.path == Utf8PathBuf::from("main.tex")
                    && &source[span.start_utf8 as usize..span.end_utf8 as usize] == "alpha,beta"
        ));
        assert_eq!(citations[1].0.command, "citet");
        assert_eq!(citations[1].0.style_hint, CitationStyleHint::Textual);
        assert_eq!(citations[1].0.keys, vec!["gamma".to_string()]);
        assert_eq!(citations[2].0.command, "parencite");
        assert_eq!(citations[2].0.style_hint, CitationStyleHint::Parenthetical);
        assert_eq!(citations[2].0.keys, vec!["delta".to_string()]);
        assert_eq!(citations[3].0.command, "textcite");
        assert_eq!(citations[3].0.style_hint, CitationStyleHint::Textual);
        assert_eq!(citations[3].0.keys, vec!["epsilon".to_string()]);
        assert_eq!(citations[4].0.command, "citep");
        assert_eq!(citations[4].0.style_hint, CitationStyleHint::Parenthetical);
        assert_eq!(citations[4].0.keys, vec!["zeta".to_string()]);
        assert_eq!(citations[5].0.command, "citealt");
        assert_eq!(citations[5].0.style_hint, CitationStyleHint::Textual);
        assert_eq!(citations[5].0.keys, vec!["eta".to_string()]);
        assert_eq!(citations[6].0.command, "citealp");
        assert_eq!(citations[6].0.style_hint, CitationStyleHint::Parenthetical);
        assert_eq!(citations[6].0.keys, vec!["theta".to_string()]);
        assert_eq!(citations[7].0.command, "Textcite");
        assert_eq!(citations[7].0.style_hint, CitationStyleHint::Textual);
        assert_eq!(citations[7].0.keys, vec!["iota".to_string()]);
        assert_eq!(citations[8].0.command, "Citealt");
        assert_eq!(citations[8].0.style_hint, CitationStyleHint::Textual);
        assert_eq!(citations[8].0.keys, vec!["lambda".to_string()]);
        assert_eq!(citations[9].0.command, "Citealp");
        assert_eq!(citations[9].0.style_hint, CitationStyleHint::Parenthetical);
        assert_eq!(citations[9].0.keys, vec!["mu".to_string()]);
    }

    #[test]
    fn render_event_capture_records_citation_metadata_aliases_without_leaking_keys() {
        let source = r"\begin{document}\Citeauthor{alpha} \Citeyear{beta} \Citeyearpar{gamma} \citetitle{delta} \Citetitle{epsilon} \citefullauthor{zeta} \Citefullauthor*{eta}\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);
        let citations = outcome
            .render_events
            .iter()
            .filter_map(|event| match &event.event {
                RenderEvent::InlineCitation(citation) => Some(citation),
                _ => None,
            })
            .collect::<Vec<_>>();

        let expected = [
            ("Citeauthor", "alpha", CitationStyleHint::Textual),
            ("Citeyear", "beta", CitationStyleHint::Textual),
            ("Citeyearpar", "gamma", CitationStyleHint::Parenthetical),
            ("citetitle", "delta", CitationStyleHint::Textual),
            ("Citetitle", "epsilon", CitationStyleHint::Textual),
            ("citefullauthor", "zeta", CitationStyleHint::Textual),
            ("Citefullauthor", "eta", CitationStyleHint::Textual),
        ];
        assert_eq!(citations.len(), expected.len());
        for (citation, (command, key, style_hint)) in citations.iter().zip(expected) {
            assert_eq!(citation.command, command);
            assert_eq!(citation.keys, vec![key.to_string()]);
            assert_eq!(citation.style_hint, style_hint);
        }
        assert!(!outcome.render_events.iter().any(|event| matches!(
            &event.event,
            RenderEvent::Text(text)
                if text.text.contains("alpha")
                    || text.text.contains("beta")
                    || text.text.contains("gamma")
                    || text.text.contains("delta")
                    || text.text.contains("epsilon")
                    || text.text.contains("zeta")
                    || text.text.contains("eta")
        )));
    }

