    #[test]
    fn render_event_capture_records_list_items_without_losing_inline_events() {
        let source = r"\begin{document}\begin{itemize}\item First \cite{key}\item[Custom] Second\end{itemize}\begin{enumerate}\item One\item Two\end{enumerate}\begin{description}\item[Term] Meaning \cite{key}\item[Other] More\end{description}\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);

        assert!(outcome.render_events.iter().any(|event| {
            matches!(
                &event.event,
                RenderEvent::BeginBlock(BeginBlockEvent {
                    block: BlockKind::List {
                        list_kind: ListKind::Unordered
                    }
                })
            )
        }));
        assert!(outcome.render_events.iter().any(|event| {
            matches!(
                &event.event,
                RenderEvent::BeginBlock(BeginBlockEvent {
                    block: BlockKind::List {
                        list_kind: ListKind::Ordered
                    }
                })
            )
        }));
        assert!(outcome.render_events.iter().any(|event| {
            matches!(
                &event.event,
                RenderEvent::BeginBlock(BeginBlockEvent {
                    block: BlockKind::List {
                        list_kind: ListKind::Description
                    }
                })
            )
        }));
        let items = outcome
            .render_events
            .iter()
            .filter_map(|event| match &event.event {
                RenderEvent::ListItem(item) => Some((item, &event.meta.source.primary)),
                _ => None,
            })
            .collect::<Vec<_>>();
        assert_eq!(items.len(), 6);
        assert_eq!(items[0].0.marker, None);
        assert_eq!(items[1].0.marker.as_deref(), Some("Custom"));
        assert!(matches!(
            items[1].1,
            tex_render_model::ProvenanceSpan::File(span)
                if span.path == Utf8PathBuf::from("main.tex")
                    && &source[span.start_utf8 as usize..span.end_utf8 as usize]
                        == r"\item[Custom]"
        ));
        assert_eq!(items[4].0.marker.as_deref(), Some("Term"));
        assert!(outcome.render_events.iter().any(|event| {
            matches!(
                &event.event,
                RenderEvent::InlineCitation(citation)
                    if citation.keys == vec!["key".to_string()]
            )
        }));
    }

    #[test]
    fn render_event_capture_records_simple_environment_blocks_without_fallback() {
        let source = r"\begin{document}\begin{quote}Quoted \cite{key}.\end{quote}\begin{center}Centered text.\end{center}\begin{theorem}Theorem text.\end{theorem}\begin{proof}Proof text.\end{proof}\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);
        let environment_begins = outcome
            .render_events
            .iter()
            .filter_map(|event| match &event.event {
                RenderEvent::BeginBlock(BeginBlockEvent {
                    block: BlockKind::Environment { name },
                }) => Some(name.as_str()),
                _ => None,
            })
            .collect::<Vec<_>>();
        let environment_ends = outcome
            .render_events
            .iter()
            .filter_map(|event| match &event.event {
                RenderEvent::EndBlock(BeginBlockEvent {
                    block: BlockKind::Environment { name },
                }) => Some(name.as_str()),
                _ => None,
            })
            .collect::<Vec<_>>();

        assert_eq!(
            environment_begins,
            vec!["quote", "center", "theorem", "proof"]
        );
        assert_eq!(
            environment_ends,
            vec!["quote", "center", "theorem", "proof"]
        );
        assert!(outcome.render_events.iter().any(|event| {
            matches!(
                &event.event,
                RenderEvent::InlineCitation(citation)
                    if citation.keys == vec!["key".to_string()]
            )
        }));
        assert!(!outcome.render_events.iter().any(|event| matches!(
            &event.event,
            RenderEvent::RawFallback(fallback)
                if matches!(
                    fallback.environment.as_deref(),
                    Some("quote" | "center" | "theorem" | "proof")
                )
        )));
    }

