    #[test]
    fn render_event_capture_records_label_definitions_without_text() {
        let source =
            r"\begin{document}\section{Intro}\label{sec:intro}See \ref{sec:intro}.\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);
        let label = outcome
            .render_events
            .iter()
            .find(|event| matches!(&event.event, RenderEvent::LabelDefinition(_)))
            .expect("label definition event");

        assert!(matches!(
            &label.event,
            RenderEvent::LabelDefinition(label)
                if label.key == "sec:intro" && label.command == "label"
        ));
        assert!(matches!(
            &label.meta.source.primary,
            tex_render_model::ProvenanceSpan::File(span)
                if span.path == Utf8PathBuf::from("main.tex")
                    && &source[span.start_utf8 as usize..span.end_utf8 as usize] == "sec:intro"
        ));
        assert!(!outcome.render_events.iter().any(|event| matches!(
            &event.event,
            RenderEvent::Text(text) if text.text.contains("sec:intro")
        )));
    }

    #[test]
    fn render_event_capture_records_section_macro_provenance() {
        let source = r"\newcommand{\mysection}[1]{\section{#1}}\begin{document}\mysection{Intro}\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);
        let heading = outcome
            .render_events
            .iter()
            .find(|event| matches!(&event.event, RenderEvent::Heading(_)))
            .expect("heading event");

        assert!(matches!(
            &heading.meta.source.primary,
            tex_render_model::ProvenanceSpan::File(span)
                if span.path == Utf8PathBuf::from("main.tex")
                    && &source[span.start_utf8 as usize..span.end_utf8 as usize] == "Intro"
        ));
        assert_eq!(heading.meta.source.expansion_stack.len(), 1);
        assert_eq!(
            heading.meta.source.expansion_stack[0]
                .command_name
                .as_deref(),
            Some("mysection")
        );
        assert!(
            heading.meta.source.expansion_stack[0]
                .definition_span
                .is_some()
        );
    }

    #[test]
    fn render_event_capture_records_title_definition_and_emit_spans() {
        let source = r"\title{A Paper}\begin{document}\maketitle\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);
        let title = outcome
            .render_events
            .iter()
            .find(|event| {
                matches!(
                    &event.event,
                    RenderEvent::SetDocumentMetadata(metadata)
                        if metadata.field == MetadataField::Title
                )
            })
            .expect("title metadata event");
        let flush = outcome
            .render_events
            .iter()
            .find(|event| matches!(&event.event, RenderEvent::FlushTitleBlock(_)))
            .expect("flush title event");

        assert!(matches!(
            &title.meta.source.primary,
            tex_render_model::ProvenanceSpan::File(span)
                if span.path == Utf8PathBuf::from("main.tex")
                    && &source[span.start_utf8 as usize..span.end_utf8 as usize] == "A Paper"
        ));
        assert!(matches!(
            &flush.meta.source.primary,
            tex_render_model::ProvenanceSpan::File(span)
                if span.path == Utf8PathBuf::from("main.tex")
                    && &source[span.start_utf8 as usize..span.end_utf8 as usize] == "\\maketitle"
        ));
    }

    #[test]
    fn render_event_capture_records_authblk_optional_authors_and_affiliations() {
        let source = r"\usepackage{authblk}\title{Quantum Paper}\author[1]{Nai-Hui Chia\thanks{nc67@rice.edu}}\author[2]{Atsuya Hasegawa}\affil[1]{\textit{Department of Computer Science}}\affil[2]{Graduate School of Mathematics}\begin{document}\maketitle\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);

        assert!(!outcome.diagnostics.iter().any(|diagnostic| {
            diagnostic.kind == VmDiagnosticKind::MissingFile
                && diagnostic.detail == "package authblk.sty"
        }));
        assert!(
            outcome
                .loaded_modules
                .contains(&Utf8PathBuf::from("authblk.sty"))
        );
        assert!(!outcome.diagnostics.iter().any(|diagnostic| {
            diagnostic.kind == VmDiagnosticKind::UndefinedControlSequence
                && matches!(diagnostic.detail.as_str(), "affil" | "thanks")
        }));
        let authors = outcome
            .render_events
            .iter()
            .filter_map(|event| match &event.event {
                RenderEvent::SetDocumentMetadata(metadata)
                    if metadata.field == MetadataField::Author =>
                {
                    Some(metadata.value.as_str())
                }
                _ => None,
            })
            .collect::<Vec<_>>();

        assert_eq!(
            authors,
            vec![
                "Nai-Hui Chia nc67@rice.edu",
                "Atsuya Hasegawa",
                "Department of Computer Science",
                "Graduate School of Mathematics"
            ]
        );
        for author in authors {
            assert!(!author.contains("[1]"));
            assert!(!author.contains("[2]"));
            assert!(!author.contains("affil"));
            assert!(!author.contains("thanks"));
        }
    }

    #[test]
    fn render_event_capture_records_footnote_bodies_with_inline_events() {
        let source = r"\begin{document}Text\footnote{Note \cite{key} and \ref{sec:intro}.} after.\footnotetext[1]{Loose note.}\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);

        let visible_text = outcome
            .render_events
            .iter()
            .filter_map(|event| match &event.event {
                RenderEvent::Text(text) => Some(text.text.as_str()),
                RenderEvent::Space(_) => Some(" "),
                RenderEvent::InlineCitation(_) | RenderEvent::InlineReference(_) => Some("[?]"),
                _ => None,
            })
            .collect::<Vec<_>>()
            .join("");
        assert!(
            visible_text.contains("Text Note [?] and [?]. after. Loose note."),
            "{visible_text}"
        );
        for hidden in ["footnote", "footnotetext", "{", "}", "key", "sec:intro"] {
            assert!(!visible_text.contains(hidden), "{visible_text}");
        }
        assert!(outcome.render_events.iter().any(|event| {
            matches!(
                &event.event,
                RenderEvent::InlineCitation(citation) if citation.keys == vec!["key".to_string()]
            )
        }));
        assert!(outcome.render_events.iter().any(|event| {
            matches!(
                &event.event,
                RenderEvent::InlineReference(reference)
                    if reference.keys == vec!["sec:intro".to_string()]
            )
        }));
    }

    #[test]
    fn render_event_capture_redacts_title_citation_and_reference_keys() {
        let source =
            r"\title{See \cite{key} and \ref{sec:intro}.}\begin{document}\maketitle\end{document}";
        let mut interner = ControlSequenceInterner::new();
        let mut vm = Vm::new(&mut interner);
        vm.set_entry_source_path("main.tex");
        vm.enable_render_event_capture();
        let outcome = vm.run_plain(source);
        let title_text = outcome
            .render_events
            .iter()
            .find_map(|event| match &event.event {
                RenderEvent::SetDocumentMetadata(metadata)
                    if metadata.field == MetadataField::Title =>
                {
                    Some(metadata.value.as_str())
                }
                _ => None,
            })
            .expect("title metadata event");

        assert_eq!(title_text, "See [?] and [?].");
        assert!(!title_text.contains("key"));
        assert!(!title_text.contains("sec:intro"));
        assert!(!title_text.contains("cite"));
        assert!(!title_text.contains("ref"));
    }
